import { useState } from "react";
import { recipes, adminUsers } from "../../data/index";

const NAV = [
  { icon: "⊞", label: "Dashboard", id: "dashboard" },
  { icon: "👥", label: "User Management", id: "users" },
  { icon: "🍴", label: "Recipes", id: "recipes" },
  { icon: "📊", label: "Analytics", id: "analytics" },
  { icon: "🔔", label: "Reports", id: "reports" },
];

export default function AdminDashboardPage({ setPage }) {
  const [activeNav, setActiveNav] = useState("dashboard");

  return (
    <div className="sidebar-layout" style={{ background:"#0d0d0f" }}>
      <aside className="sidebar sidebar-dark">
        <div className="sidebar-brand sidebar-brand-dark">
          <div className="sidebar-brand-icon">✕</div>
          <div>
            <div className="sidebar-brand-name sidebar-brand-name-light">Admin Console</div>
            <div className="sidebar-brand-sub">Recipe Platform</div>
          </div>
        </div>

        <div className="sidebar-nav">
          {NAV.map(item => (
            <button key={item.id} className={`sidebar-item sidebar-item-dark ${activeNav === item.id ? "active" : ""}`} onClick={() => setActiveNav(item.id)}>
              <span>{item.icon}</span>{item.label}
            </button>
          ))}
        </div>

        <div className="sidebar-bottom sidebar-bottom-dark">
          <button className="sidebar-item sidebar-item-dark">⚙ Settings</button>
          <div className="sidebar-profile sidebar-profile-dark">
            <div className="sidebar-avatar" style={{ width:30, height:30, fontSize:11 }}>CA</div>
            <div>
              <div className="sidebar-profile-name sidebar-profile-name-dark">Chief Admin</div>
              <div className="sidebar-profile-role">Sys #34</div>
            </div>
          </div>
          <button className="logout-btn" onClick={() => setPage("login")}>↩ Logout</button>
        </div>
      </aside>

      <div className="page-content" style={{ background:"#0d0d0f" }}>
        {activeNav === "dashboard" && <AdminOverview setActiveNav={setActiveNav} />}
        {activeNav === "users" && <AdminUsers />}
        {activeNav === "recipes" && <AdminRecipes />}
        {activeNav === "analytics" && <AdminAnalytics />}
        {activeNav === "reports" && <AdminReports />}
      </div>
    </div>
  );
}

// ── OVERVIEW ──
function AdminOverview({ setActiveNav }) {
  return (
    <>
      <div className="page-header">
        <div>
          <h1 className="page-title page-title-light">Dashboard</h1>
          <p className="page-sub" style={{ color:"#555" }}>Platform overview and key metrics.</p>
        </div>
      </div>
      <div className="stats-row" style={{ gridTemplateColumns:"repeat(4,1fr)" }}>
        {[["👥","Total Users","1,248","+12% this month","#eef4ff"],["🍴","Total Recipes","3,891","+8% this month","#fff0f0"],["👨‍🍳","Verified Chefs","342","+5 this week","#f0faf4"],["⭐","Avg Platform Rating","4.7","Across all recipes","#fffbea"]].map(([icon,label,val,sub,bg]) => (
          <div key={label} className="stat-card stat-card-dark">
            <div className="stat-icon" style={{background:bg}}>{icon}</div>
            <div>
              <div className="stat-val stat-val-light">{val}</div>
              <div className="stat-label">{label}</div>
              <div style={{fontSize:11,color:"#3aab5e",marginTop:2}}>{sub}</div>
            </div>
          </div>
        ))}
      </div>
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:20 }}>
        <div style={{ background:"#111114", border:"1px solid rgba(255,255,255,.06)", borderRadius:12, padding:22 }}>
          <div style={{ fontSize:14, fontWeight:600, color:"#fff", marginBottom:16 }}>Recent Activity</div>
          {[["Marco Rossi submitted a new recipe","2 min ago","#3aab5e"],["Elena Smith account suspended","15 min ago","#e85d2f"],["Aisha Kamal chef application pending","1 hr ago","#e8b82f"],["New user registered: John Park","2 hrs ago","#1a7eb8"]].map(([msg,time,color]) => (
            <div key={msg} style={{ display:"flex", alignItems:"flex-start", gap:10, padding:"10px 0", borderBottom:"1px solid rgba(255,255,255,.04)" }}>
              <div style={{ width:8, height:8, borderRadius:"50%", background:color, marginTop:5, flexShrink:0 }} />
              <div>
                <div style={{ fontSize:13, color:"#ccc" }}>{msg}</div>
                <div style={{ fontSize:11, color:"#555", marginTop:2 }}>{time}</div>
              </div>
            </div>
          ))}
        </div>
        <div style={{ background:"#111114", border:"1px solid rgba(255,255,255,.06)", borderRadius:12, padding:22 }}>
          <div style={{ fontSize:14, fontWeight:600, color:"#fff", marginBottom:16 }}>Pending Actions</div>
          {[["Chef verifications pending","3 applications",() => setActiveNav("users"),"#e8b82f"],["Recipes under review","7 recipes",() => setActiveNav("recipes"),"#1a7eb8"],["Reported content","2 reports",() => setActiveNav("reports"),"#e85d2f"]].map(([title,count,action,color]) => (
            <div key={title} style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"12px 0", borderBottom:"1px solid rgba(255,255,255,.04)" }}>
              <div>
                <div style={{ fontSize:13, color:"#ccc" }}>{title}</div>
                <div style={{ fontSize:11, color:color, fontWeight:600, marginTop:2 }}>{count}</div>
              </div>
              <button onClick={action} style={{ background:"rgba(255,255,255,.06)", border:"1px solid rgba(255,255,255,.08)", color:"#aaa", padding:"5px 12px", borderRadius:7, fontSize:12 }}>Review</button>
            </div>
          ))}
        </div>
      </div>
    </>
  );
}

// ── USER MANAGEMENT ──
function AdminUsers() {
  const [users, setUsers] = useState(adminUsers);
  const [search, setSearch] = useState("");
  const [showModal, setShowModal] = useState(false);
  const [newUser, setNewUser] = useState({ name: "", email: "", role: "User" });

  const filtered = users.filter(u => !search || u.name.toLowerCase().includes(search.toLowerCase()) || u.email.toLowerCase().includes(search.toLowerCase()));

  const handleAdd = () => {
    if (!newUser.name || !newUser.email) return;
    setUsers(prev => [...prev, { id: Date.now(), name: newUser.name, email: newUser.email, avatar: newUser.name.split(" ").map(n=>n[0]).join("").slice(0,2).toUpperCase(), avatarBg:"#2980b9", role: newUser.role, verification: newUser.role === "Chef" ? "VERIFY CHEF APPLICATION" : "Not Applicable", verificationStatus: newUser.role === "Chef" ? "pending" : "na", status:"Pending", statusType:"pending" }]);
    setShowModal(false);
    setNewUser({ name:"", email:"", role:"User" });
  };

  return (
    <>
      <div className="page-header">
        <div>
          <h1 className="page-title page-title-light">User Management</h1>
          <p className="page-sub" style={{color:"#555"}}>Manage system users, roles, and account verifications.</p>
        </div>
        <button className="action-cta" onClick={() => setShowModal(true)}>✦ Add New User</button>
      </div>

      <div style={{ display:"flex", gap:12, marginBottom:16 }}>
        <div style={{ flex:1, position:"relative" }}>
          <span style={{ position:"absolute", left:13, top:"50%", transform:"translateY(-50%)", color:"#444" }}>🔍</span>
          <input style={{ width:"100%", background:"#18181c", border:"1px solid rgba(255,255,255,.07)", borderRadius:8, padding:"10px 14px 10px 38px", fontSize:13, color:"#ccc", outline:"none" }}
            placeholder="Search by name, email, or ID..." value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        {["≡ All Roles ▾","◎ Account Status ▾"].map(f => (
          <button key={f} style={{ background:"#18181c", border:"1px solid rgba(255,255,255,.07)", borderRadius:8, padding:"9px 14px", fontSize:12, fontWeight:500, color:"#888", whiteSpace:"nowrap" }}>{f}</button>
        ))}
      </div>

      <div style={{ background:"#111114", border:"1px solid rgba(255,255,255,.06)", borderRadius:12, overflow:"hidden" }}>
        <table style={{ width:"100%", borderCollapse:"collapse" }}>
          <thead>
            <tr style={{ background:"rgba(255,255,255,.03)", borderBottom:"1px solid rgba(255,255,255,.06)" }}>
              {["User Details","Current Role","Verification","Status","Actions"].map(h => (
                <th key={h} style={{ padding:"12px 20px", fontSize:11, fontWeight:600, color:"#555", letterSpacing:".8px", textTransform:"uppercase", textAlign:"left" }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map(user => (
              <tr key={user.id} style={{ borderBottom:"1px solid rgba(255,255,255,.04)" }}>
                <td style={{ padding:"16px 20px" }}>
                  <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                    <div style={{ width:36, height:36, borderRadius:"50%", background:user.avatarBg, display:"flex", alignItems:"center", justifyContent:"center", fontSize:13, fontWeight:700, color:"#fff", flexShrink:0 }}>{user.avatar}</div>
                    <div>
                      <div style={{ fontSize:14, fontWeight:600, color:"#e85d2f" }}>{user.name}</div>
                      <div style={{ fontSize:12, color:"#555" }}>{user.email}</div>
                    </div>
                  </div>
                </td>
                <td style={{ padding:"16px 20px" }}>
                  <span style={{ background:"rgba(255,255,255,.06)", border:"1px solid rgba(255,255,255,.08)", color:"#aaa", padding:"3px 10px", borderRadius:6, fontSize:12 }}>{user.role} ▾</span>
                </td>
                <td style={{ padding:"16px 20px" }}>
                  {user.verificationStatus === "verified" && <span style={{ background:"rgba(58,171,94,.1)", border:"1px solid rgba(58,171,94,.25)", color:"#3aab5e", padding:"4px 12px", borderRadius:6, fontSize:11, fontWeight:700 }}>✔ {user.verification}</span>}
                  {user.verificationStatus === "pending" && <button style={{ background:"#3aab5e", color:"#fff", border:"none", padding:"5px 12px", borderRadius:6, fontSize:11, fontWeight:700 }}>{user.verification}</button>}
                  {user.verificationStatus === "na" && <span style={{ fontSize:13, color:"#444" }}>{user.verification}</span>}
                </td>
                <td style={{ padding:"16px 20px" }}>
                  <div style={{ display:"flex", alignItems:"center", gap:10 }}>
                    <span style={{ display:"flex", alignItems:"center", gap:6, fontSize:13, fontWeight:500, color: user.statusType === "active" ? "#3aab5e" : user.statusType === "suspended" ? "#e85d2f" : "#888" }}>
                      <span style={{ width:7, height:7, borderRadius:"50%", background: user.statusType === "active" ? "#3aab5e" : user.statusType === "suspended" ? "#e85d2f" : "#888", display:"inline-block" }} />
                      {user.status}
                    </span>
                    {user.statusType === "suspended" && (
                      <button style={{ background:"rgba(232,93,47,.12)", border:"1px solid rgba(232,93,47,.3)", color:"#e85d2f", padding:"3px 10px", borderRadius:6, fontSize:11, fontWeight:700 }}>REACTIVATE</button>
                    )}
                  </div>
                </td>
                <td style={{ padding:"16px 20px" }}>
                  <div style={{ display:"flex", gap:6 }}>
                    {["🕐","⋮"].map(icon => (
                      <button key={icon} style={{ width:30, height:30, borderRadius:6, background:"rgba(255,255,255,.04)", border:"1px solid rgba(255,255,255,.06)", color:"#555", fontSize:13 }}>{icon}</button>
                    ))}
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", padding:"14px 20px", borderTop:"1px solid rgba(255,255,255,.05)" }}>
          <span style={{ fontSize:12, color:"#555" }}>Showing 1–{filtered.length} of {users.length} users</span>
          <div style={{ display:"flex", gap:4 }}>
            {["‹","›"].map(a => <button key={a} style={{ width:28, height:28, borderRadius:6, background:"rgba(255,255,255,.04)", border:"1px solid rgba(255,255,255,.06)", color:"#666", fontSize:13 }}>{a}</button>)}
          </div>
        </div>
      </div>

      {showModal && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.7)", display:"flex", alignItems:"center", justifyContent:"center", zIndex:100, backdropFilter:"blur(4px)" }} onClick={() => setShowModal(false)}>
          <div style={{ background:"#18181c", border:"1px solid rgba(255,255,255,.08)", borderRadius:14, padding:28, width:420 }} onClick={e => e.stopPropagation()}>
            <div style={{ fontFamily:"'Syne',sans-serif", fontSize:18, fontWeight:700, color:"#fff", marginBottom:6 }}>Add New User</div>
            <div style={{ fontSize:13, color:"#555", marginBottom:24 }}>Create a new user account on the platform.</div>
            {[["Full Name","text","e.g. Marco Rossi","name"],["Email Address","email","e.g. user@example.com","email"]].map(([label,type,ph,key]) => (<div key={key}>
              <label style={{ fontSize:12, fontWeight:600, color:"#777", letterSpacing:".5px", textTransform:"uppercase", marginBottom:6, display:"block" }}>{label}</label>
              <input style={{ width:"100%", background:"#111114", border:"1px solid rgba(255,255,255,.08)", borderRadius:8, padding:"10px 14px", fontSize:13, color:"#ccc", outline:"none", marginBottom:16 }}
                type={type} placeholder={ph} value={newUser[key]} onChange={e => setNewUser(f => ({...f,[key]:e.target.value}))} />
            </div>))}
            <label style={{ fontSize:12, fontWeight:600, color:"#777", letterSpacing:".5px", textTransform:"uppercase", marginBottom:6, display:"block" }}>Role</label>
            <select style={{ width:"100%", background:"#111114", border:"1px solid rgba(255,255,255,.08)", borderRadius:8, padding:"10px 14px", fontSize:13, color:"#ccc", outline:"none", marginBottom:24, appearance:"none" }}
              value={newUser.role} onChange={e => setNewUser(f => ({...f,role:e.target.value}))}>
              <option>User</option><option>Chef</option><option>Admin</option>
            </select>
            <div style={{ display:"flex", gap:10, justifyContent:"flex-end" }}>
              <button onClick={() => setShowModal(false)} style={{ background:"rgba(255,255,255,.05)", border:"1px solid rgba(255,255,255,.08)", color:"#888", padding:"9px 18px", borderRadius:8, fontSize:13 }}>Cancel</button>
              <button onClick={handleAdd} style={{ background:"#e85d2f", border:"none", color:"#fff", padding:"9px 20px", borderRadius:8, fontSize:13, fontWeight:600 }}>Add User</button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

// ── RECIPES ──
function AdminRecipes() {
  const [activeTab, setActiveTab] = useState("All");
  const tabs = ["All","Live","Pending Review","Rejected"];
  const filtered = activeTab === "All" ? recipes : recipes.filter(r => r.status === activeTab);
  return (
    <>
      <div className="page-header">
        <div><h1 className="page-title page-title-light">Recipe Management</h1><p className="page-sub" style={{color:"#555"}}>Review and manage all platform recipes.</p></div>
      </div>
      <div className="tab-bar tab-bar-dark" style={{marginBottom:22}}>
        {tabs.map(t => <button key={t} className={`tab-btn ${activeTab===t?"active":""}`} onClick={()=>setActiveTab(t)} style={{color: activeTab===t?"#e85d2f":"#555"}}>{t}</button>)}
      </div>
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(260px,1fr))", gap:18 }}>
        {filtered.map(r => (
          <div key={r.id} style={{ background:"#111114", border:"1px solid rgba(255,255,255,.06)", borderRadius:12, overflow:"hidden" }}>
            <div style={{ position:"relative" }}>
              <img src={r.image} alt={r.title} style={{ width:"100%", height:140, objectFit:"cover", display:"block" }} />
              <span style={{ position:"absolute", top:10, left:10, fontSize:10, fontWeight:700, padding:"3px 8px", borderRadius:99, letterSpacing:".5px", textTransform:"uppercase",
                background: r.status === "Live" ? "rgba(58,171,94,.15)" : r.status === "Pending Review" ? "rgba(232,180,47,.15)" : "rgba(232,93,47,.15)",
                color: r.status === "Live" ? "#3aab5e" : r.status === "Pending Review" ? "#e8b82f" : "#e85d2f" }}>● {r.status}</span>
            </div>
            <div style={{ padding:14 }}>
              <div style={{ fontSize:14, fontWeight:600, color:"#ddd", marginBottom:4 }}>{r.title}</div>
              <div style={{ fontSize:12, color:"#555", marginBottom:10 }}>{r.chef}</div>
              <div style={{ display:"flex", gap:8 }}>
                <button style={{ flex:1, background:"rgba(255,255,255,.04)", border:"1px solid rgba(255,255,255,.06)", color:"#888", padding:"6px", borderRadius:7, fontSize:12 }}>✏ Edit</button>
                {r.status === "Pending Review" && <button style={{ flex:1, background:"rgba(58,171,94,.12)", border:"1px solid rgba(58,171,94,.25)", color:"#3aab5e", padding:"6px", borderRadius:7, fontSize:12, fontWeight:600 }}>✓ Approve</button>}
                {r.status !== "Pending Review" && <button style={{ flex:1, background:"rgba(232,93,47,.08)", border:"1px solid rgba(232,93,47,.2)", color:"#e85d2f", padding:"6px", borderRadius:7, fontSize:12 }}>🗑 Delete</button>}
              </div>
            </div>
          </div>
        ))}
      </div>
    </>
  );
}

// ── ANALYTICS ──
function AdminAnalytics() {
  const months = ["Jan","Feb","Mar","Apr","May","Jun"];
  const values = [820, 1240, 980, 1560, 1340, 1890];
  const maxVal = Math.max(...values);
  return (
    <>
      <div className="page-header"><div><h1 className="page-title page-title-light">Analytics</h1><p className="page-sub" style={{color:"#555"}}>Platform performance and growth metrics.</p></div></div>
      <div className="stats-row" style={{gridTemplateColumns:"repeat(4,1fr)"}}>
        {[["📈","Monthly Growth","+18%","#f0faf4"],["👁","Monthly Views","89.2k","#eef4ff"],["🔄","Retention Rate","72%","#fffbea"],["💰","Revenue","$12.4k","#fff0f0"]].map(([icon,label,val,bg]) => (
          <div key={label} className="stat-card stat-card-dark"><div className="stat-icon" style={{background:bg}}>{icon}</div><div><div className="stat-val stat-val-light">{val}</div><div className="stat-label">{label}</div></div></div>
        ))}
      </div>
      <div style={{background:"#111114",border:"1px solid rgba(255,255,255,.06)",borderRadius:12,padding:24}}>
        <div style={{fontSize:14,fontWeight:600,color:"#fff",marginBottom:24}}>Recipe Views — Last 6 Months</div>
        <div style={{display:"flex",alignItems:"flex-end",gap:16,height:160}}>
          {months.map((m, i) => (
            <div key={m} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:8}}>
              <div style={{fontSize:11,color:"#e85d2f",fontWeight:600}}>{values[i] >= 1000 ? (values[i]/1000).toFixed(1)+"k" : values[i]}</div>
              <div style={{width:"100%",background:"linear-gradient(to top,#e85d2f,#c0392b)",borderRadius:"4px 4px 0 0",height:`${(values[i]/maxVal)*120}px`,transition:"height .3s"}} />
              <div style={{fontSize:12,color:"#555"}}>{m}</div>
            </div>
          ))}
        </div>
      </div>
    </>
  );
}

